package fundamentals;

public class EvenOrNot {

	public static void main(String[] args) {
		int n=13;
		if(n%2==0)
		{
			System.out.println(+n+" is an Even number");
		}
		else
		{
			System.out.println(+n+" is not a Even number");
		}
		// TODO Auto-generated method stub

	}

}
